import React, { useState, useEffect } from 'react';
import axios from 'axios';

function OrdersManager({ token }) {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');

  useEffect(() => {
    loadOrders();
  }, []);

  const loadOrders = async () => {
    try {
      const response = await axios.get('/admin/orders');
      setOrders(response.data);
    } catch (err) {
      setMessage('Failed to load orders');
    }
  };

  const updateStatus = async (orderId, status) => {
    if (!window.confirm(`Set status to ${status}?`)) return;
    setLoading(true);
    try {
      await axios.put(`/orders/${orderId}/status`, { status });
      setMessage(`Order ${status.toLowerCase()} updated`);
      loadOrders();
    } catch (err) {
      setMessage('Update failed');
    }
    setLoading(false);
  };

  return (
    <div className="container-fluid mt-4">
      <h4>Orders & Payments Management</h4>
      {message && <div className={`alert alert-${message.includes('failed') ? 'danger' : 'success'}`} role="alert">{message}</div>}
      
      <div className="table-responsive">
        <table className="table table-hover">
          <thead className="table-dark">
            <tr>
              <th>ID</th>
              <th>Phone</th>
              <th>Exams</th>
              <th>Total (KSh)</th>
              <th>Status</th>
              <th>Payment ID</th>
              <th>Date</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {orders.map(order => (
              <tr key={order.id}>
                <td>{order.id.slice(-8)}</td>
                <td>{order.user_phone}</td>
                <td>
                  {order.exam_ids ? JSON.parse(order.exam_ids).join(', ') : 'N/A'}
                </td>
                <td>{order.total_amount}</td>
                <td>
                  <span className={`badge bg-${order.status === 'paid' ? 'success' : order.status === 'pending' ? 'warning' : 'danger'}`}>
                    {order.status}
                  </span>
                </td>
                <td>{order.payment_id || 'N/A'}</td>
                <td>{new Date(order.timestamp).toLocaleDateString()}</td>
                <td>
                  <div className="btn-group btn-group-sm" role="group">
                    {order.status === 'pending' && (
                      <button className="btn btn-outline-success" onClick={() => updateStatus(order.id, 'paid')}>
                        Mark Paid
                      </button>
                    )}
                    {order.status === 'paid' && (
                      <button className="btn btn-outline-warning" onClick={() => updateStatus(order.id, 'refunded')}>
                        Refund
                      </button>
                    )}
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      {orders.length === 0 && <p className="text-muted">No orders yet. Test via mobile app.</p>}
    </div>
  );
}

export default OrdersManager;
